# Package name validation pattern (alphanumeric, hyphens, underscores, dots)
ALLOWED_PACKAGE_CHARS = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_.')
