def validate_package_name(package_spec):
    """Validate package specification to prevent injection attacks."""
    if not package_spec or not isinstance(package_spec, str):
        return False
    
    # Split package name and version specifier
    parts = package_spec.split('[')[0]  # Remove extras
    for op in ['>=', '<=', '==', '!=', '~=', '>', '<']:
        if op in parts:
            name, version = parts.split(op, 1)
            if not all(c in ALLOWED_VERSION_CHARS for c in version):
                return False
            parts = name
            break
    
    # Validate package name
    if not all(c in ALLOWED_PACKAGE_CHARS for c in parts.strip()):
        return False
    
    # Additional checks
    if len(package_spec) > 200:  # Reasonable max length
        return False
    
    if '..' in package_spec or package_spec.startswith('-'):
        return False
    
    return True

def validate_url(url):
    """Validate that URL is in allowlist and uses HTTPS."""
